<?php
error_reporting(E_ALL);ini_set('display_errors',isset($_GET['debug'])?'1':'0');session_start();
function h($s){return htmlspecialchars((string)$s,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8');}
function db(){static $p;if($p)return$p;foreach([__DIR__.'/../../database.php',__DIR__.'/../database.php']as$f){if(is_file($f)){require_once$f;break;}}if(function_exists('ho_db'))$p=ho_db();elseif(($GLOBALS['pdo']??null)instanceof PDO)$p=$GLOBALS['pdo'];else throw new Exception('No DB connection found.');$p->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);$p->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE,PDO::FETCH_ASSOC);return$p;}
function setup($p){$p->exec("CREATE TABLE IF NOT EXISTS wmt_settings(k VARCHAR(80) PRIMARY KEY,v LONGTEXT,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$p->exec("CREATE TABLE IF NOT EXISTS wmt_associates(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL UNIQUE,team VARCHAR(40) NOT NULL DEFAULT 'Services',role_type VARCHAR(80) NOT NULL DEFAULT 'AP Service TA',can_cover TINYINT(1) NOT NULL DEFAULT 1,preferred_door VARCHAR(20) NOT NULL DEFAULT 'Either',active TINYINT(1) NOT NULL DEFAULT 1,reliability DECIMAL(5,2) NOT NULL DEFAULT 3.00,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$p->exec("CREATE TABLE IF NOT EXISTS wmt_shifts(id INT AUTO_INCREMENT PRIMARY KEY,work_date DATE NOT NULL,associate_id INT NULL,associate_name VARCHAR(120) NOT NULL,team VARCHAR(40) NOT NULL DEFAULT 'Services',role_type VARCHAR(80) NOT NULL DEFAULT 'AP Service TA',start_time TIME NOT NULL,end_time TIME NOT NULL,notes TEXT,source_file VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,KEY work_date(work_date),KEY associate_id(associate_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");try{$p->exec("ALTER TABLE wmt_shifts ADD COLUMN source_file VARCHAR(255) NULL");}catch(Exception$e){}$p->exec("CREATE TABLE IF NOT EXISTS wmt_html_imports(id INT AUTO_INCREMENT PRIMARY KEY,filename VARCHAR(255),imported_rows INT NOT NULL DEFAULT 0,week_start DATE NULL,date_min DATE NULL,date_max DATE NULL,message TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");}
function setting($p,$k){$s=$p->prepare('SELECT v FROM wmt_settings WHERE k=?');$s->execute([$k]);$v=$s->fetchColumn();return$v===false?null:$v;}
function login(){echo'<!doctype html><title>Login</title><body style="font-family:system-ui;background:#f4f1ea"><form method=post style="max-width:420px;margin:12vh auto;background:white;padding:28px;border-radius:18px"><h1>AP Services Login</h1><input type=hidden name=form value=login><input type=password name=password placeholder=Password style="width:100%;padding:12px"><button style="width:100%;padding:12px;margin-top:10px;background:#223b2a;color:white;font-weight:800">Continue</button></form>';exit;}
function auth($p){$hash=setting($p,'admin_hash');if(!$hash){header('Location:index.php');exit;}if(($_POST['form']??'')==='login'&&password_verify($_POST['password']??'',$hash)){$_SESSION['wmt']=1;header('Location:import_html.php');exit;}if(empty($_SESSION['wmt']))login();}
function clean($html){$s=html_entity_decode(preg_replace('/<[^>]+>/', ' ', $html),ENT_QUOTES|ENT_HTML5,'UTF-8');return trim(preg_replace('/\s+/',' ',$s));}
function team($role){$x=strtolower($role);if(strpos($x,'invest')!==false)return'Investigator';if(strpos($x,'lead')!==false)return'Team Lead';if(strpos($x,'ops')!==false||strpos($x,'operation')!==false)return'Ops';return'Services';}
function up_assoc($p,$name,$role,$notes=''){$tm=team($role);$can=$tm==='Investigator'?0:1;$p->prepare("INSERT INTO wmt_associates(name,team,role_type,can_cover,preferred_door,notes) VALUES(?,?,?,?,?,?) ON DUPLICATE KEY UPDATE team=VALUES(team),role_type=VALUES(role_type),can_cover=VALUES(can_cover),notes=VALUES(notes)")->execute([$name,$tm,$role,$can,'Either',$notes]);$id=(int)$p->lastInsertId();if(!$id){$q=$p->prepare('SELECT id FROM wmt_associates WHERE name=?');$q->execute([$name]);$id=(int)$q->fetchColumn();}return$id;}
function mon($m){$map=['jan'=>1,'feb'=>2,'mar'=>3,'apr'=>4,'may'=>5,'jun'=>6,'jul'=>7,'aug'=>8,'sep'=>9,'oct'=>10,'nov'=>11,'dec'=>12];return$map[strtolower(substr($m,0,3))]??0;}
function start_date($html,$heads,$override){if($override&&preg_match('/^\d{4}-\d{2}-\d{2}$/',$override))return$override;if(!$heads)return date('Y-m-d');$day=$heads[0][0];$dow=$heads[0][1];$txt=clean($html);$year=(int)date('Y');if(preg_match('/\b[A-Za-z]{3,9}\s+(20\d{2})\b/',$txt,$y))$year=(int)$y[1];if(preg_match_all('/\b(Sat|Sun|Mon|Tue|Wed|Thu|Fri),\s*([A-Za-z]{3})\s*(\d{1,2})\s*-\s*(Sat|Sun|Mon|Tue|Wed|Thu|Fri),\s*([A-Za-z]{3})\s*(\d{1,2})/i',$txt,$ms,PREG_SET_ORDER)){foreach($ms as$m){if((int)$m[3]===$day&&ucfirst(strtolower($m[1]))===$dow){$mo=mon($m[2]);if($mo)return sprintf('%04d-%02d-%02d',$year,$mo,$day);}}}$best='';$bd=999999;$now=strtotime(date('Y-m-d'));for($y=$year-1;$y<=$year+1;$y++)for($mo=1;$mo<=12;$mo++){if(!checkdate($mo,$day,$y))continue;$ts=strtotime(sprintf('%04d-%02d-%02d',$y,$mo,$day));if(date('D',$ts)===$dow&&abs($ts-$now)<$bd){$bd=abs($ts-$now);$best=date('Y-m-d',$ts);}}return$best?:date('Y-m-d');}
function plus($date,$i){$d=new DateTime($date);if($i)$d->modify("+$i days");return$d->format('Y-m-d');}
function t24($hm,$ap=''){preg_match('/^(\d{1,2}):(\d{2})$/',trim($hm),$m);$h=(int)$m[1];$mi=(int)$m[2];$ap=strtolower($ap);if($ap==='pm'&&$h!==12)$h+=12;if($ap==='am'&&$h===12)$h=0;return sprintf('%02d:%02d',$h,$mi);}
function parse_html($html,$fn,$override=''){$rows=[];$sk=0;if(!preg_match_all('/<tr\b[^>]*>(.*?)<\/tr>/is',$html,$trs))return[[],date('Y-m-d'),'No table rows found.'];preg_match_all('/<t[dh]\b[^>]*>(.*?)<\/t[dh]>/is',$trs[1][0],$hc);$heads=[];for($i=2;$i<count($hc[1]);$i++){if(preg_match('/\b(\d{1,2})\s+(Sat|Sun|Mon|Tue|Wed|Thu|Fri)\b/i',clean($hc[1][$i]),$m))$heads[]=[(int)$m[1],ucfirst(strtolower($m[2]))];}$start=start_date($html,$heads,$override);for($r=1;$r<count($trs[1]);$r++){preg_match_all('/<td\b[^>]*>(.*?)<\/td>/is',$trs[1][$r],$td);if(count($td[1])<3)continue;$first=clean($td[1][0]);if(!preg_match('/^(.+?)\s+AP\s+/i',$first,$nm))continue;$name=trim($nm[1]);$max=min(count($heads),count($td[1])-2);for($i=0;$i<$max;$i++){$txt=clean($td[1][$i+2]);if(!preg_match('/\b(AP\s+(?:Service TA|Operations TA|Team Lead|Investigator))(?:\s+\d+-\d+-\d+)?\b/i',$txt,$rm)){$sk++;continue;}$role=trim($rm[1]);if(!preg_match('/(\d{1,2}:\d{2})\s*(am|pm)?\s*(?:–|-|to)\s*(\d{1,2}:\d{2})\s*(am|pm)?/i',$txt,$tm)){$sk++;continue;}$rows[]=['date'=>plus($start,$i),'name'=>$name,'team'=>team($role),'role'=>$role,'start'=>t24($tm[1],$tm[2]??''),'end'=>t24($tm[3],$tm[4]??''),'notes'=>'Imported from '.$fn];}}return[$rows,$start,'Parsed '.count($rows).' scheduled shifts from '.$fn.'. Week start '.$start.'. Skipped non-shift cells: '.$sk.'.'];}
function render($msg='',$prev=[]){echo'<!doctype html><meta name=viewport content="width=device-width,initial-scale=1"><title>HTML Import</title><style>body{font-family:system-ui;background:#f4f1ea;margin:0}.top{background:#223b2a;color:white}.wrap{max-width:1100px;margin:auto;padding:18px}.top a{color:white;margin-right:14px;font-weight:800}.card{background:white;border:1px solid #ddd2bf;border-radius:16px;padding:16px;margin:14px 0}button{background:#223b2a;color:white;font-weight:800;padding:10px;border-radius:9px;border:0}input{padding:8px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ddd;padding:7px;text-align:left}th{background:#f1eadc}.muted{color:#666}</style><div class=top><div class=wrap><b>AP Services HTML Import</b> <a href=index.php>Dashboard</a><a href=import_html.php>HTML Import</a><a href="index.php?v=week">Week</a></div></div><main class=wrap>';if($msg)echo'<div class=card><b>Result:</b> '.h($msg).'</div>';echo'<div class=card><h1>Upload WPP Scheduler HTML</h1><p>Upload a saved Scheduler page. It imports AP scheduled shift cards and ignores Available/Unavailable/PTO cells.</p><form method=post enctype=multipart/form-data><input type=hidden name=form value=upload><p><input type=file name=htmlfile accept=".html,.htm,text/html" required></p><p>Week start override <input type=date name=week_start> <span class=muted>Leave blank unless dates parse wrong.</span></p><p><label><input type=checkbox name=replace_dates value=1 checked> Replace existing shifts for imported dates</label></p><button>Import HTML schedule</button></form></div>';if($prev){echo'<div class=card><h2>Preview</h2><table><tr><th>Date</th><th>Name</th><th>Team</th><th>Role</th><th>Shift</th></tr>';foreach(array_slice($prev,0,80)as$r)echo'<tr><td>'.h($r['date']).'</td><td>'.h($r['name']).'</td><td>'.h($r['team']).'</td><td>'.h($r['role']).'</td><td>'.h($r['start'].'-'.$r['end']).'</td></tr>';echo'</table></div>';}echo'</main>';}
try{$p=db();setup($p);auth($p);$msg='';$prev=[];if($_SERVER['REQUEST_METHOD']==='POST'&&($_POST['form']??'')==='upload'){if(empty($_FILES['htmlfile'])||$_FILES['htmlfile']['error']!==UPLOAD_ERR_OK)throw new Exception('No HTML file uploaded.');$fn=basename($_FILES['htmlfile']['name']);$html=file_get_contents($_FILES['htmlfile']['tmp_name']);list($rows,$start,$msg)=parse_html($html,$fn,trim($_POST['week_start']??''));if($rows){$dates=[];foreach($rows as$r)$dates[$r['date']]=1;if(!empty($_POST['replace_dates']))foreach(array_keys($dates)as$d)$p->prepare('DELETE FROM wmt_shifts WHERE work_date=?')->execute([$d]);foreach($rows as$r){$id=up_assoc($p,$r['name'],$r['role'],$r['notes']);$p->prepare('INSERT INTO wmt_shifts(work_date,associate_id,associate_name,team,role_type,start_time,end_time,notes,source_file) VALUES(?,?,?,?,?,?,?,?,?)')->execute([$r['date'],$id,$r['name'],$r['team'],$r['role'],$r['start'],$r['end'],$r['notes'],$fn]);}$ks=array_keys($dates);sort($ks);$p->prepare('INSERT INTO wmt_html_imports(filename,imported_rows,week_start,date_min,date_max,message) VALUES(?,?,?,?,?,?)')->execute([$fn,count($rows),$start,$ks[0],end($ks),$msg]);$msg.=' Imported dates '.implode(', ',$ks).'.';$prev=$rows;}else$msg.=' No schedules imported. This may be an Availability view.';}render($msg,$prev);}catch(Throwable$e){http_response_code(500);render('Error: '.$e->getMessage());}
